class Solution {
public:
    int countWinningSequences(string s) {
        const int MOD = 1e9 + 7;
        int n = s.size();
        vector<vector<vector<int>>> dp(n + 1, vector<vector<int>>(3, vector<int>(3, 0)));
        dp[0][0][0] = 1;
        dp[0][1][1] = 1;
        dp[0][2][2] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < 3; j++) {
                for (int k = 0; k < 3; k++) {
                    if (j == 0 && k == 1) {
                        dp[i][1][0] = (dp[i][1][0] + dp[i - 1][j][k]) % MOD;
                        dp[i][2][0] = (dp[i][2][0] + dp[i - 1][j][k]) % MOD;
                    } else if (j == 1 && k == 2) {
                        dp[i][0][1] = (dp[i][0][1] + dp[i - 1][j][k]) % MOD;
                        dp[i][2][1] = (dp[i][2][1] + dp[i - 1][j][k]) % MOD;
                    } else if (j == 2 && k == 0) {
                        dp[i][0][2] = (dp[i][0][2] + dp[i - 1][j][k]) % MOD;
                        dp[i][1][2] = (dp[i][1][2] + dp[i - 1][j][k]) % MOD;
                    } else {
                        if (s[i - 1] == 'F' && k == 1) {
                            dp[i][0][0] = (dp[i][0][0] + dp[i - 1][j][k]) % MOD;
                            dp[i][2][0] = (dp[i][2][0] + dp[i - 1][j][k]) % MOD;
                        } else if (s[i - 1] == 'W' && k == 2) {
                            dp[i][0][1] = (dp[i][0][1] + dp[i - 1][j][k]) % MOD;
                            dp[i][1][1] = (dp[i][1][1] + dp[i - 1][j][k]) % MOD;
                        } else if (s[i - 1] == 'E' && k == 0) {
                            dp[i][1][2] = (dp[i][1][2] + dp[i - 1][j][k]) % MOD;
                            dp[i][2][2] = (dp[i][2][2] + dp[i - 1][j][k]) % MOD;
                        }
                    }
                }
            }
        }
        int ans = 0;
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                ans = (ans + dp[n][i][j]) % MOD;
            }
        }
        return ans;
    }
};
